_G.IsPtrValid = function(ptr)
    if ptr == nil then return false end
    return slua.isValid(ptr)
end

function _G.apply_attachment(CurWeapon, avatarid)
    local array = CurWeapon.synData
    for AttachIdx = 0, 4 do
        local isrefresh = false
        local Data = array:Get(AttachIdx)
        if not Data then break end
        
        local itemid = slua.IndexReference(Data, "defineID").TypeSpecificID
        if itemid and itemid < 10000000 and itemid > 0 then
            if AttachIdx == 0 then
                Data.defineID.TypeSpecificID, isrefresh = _G.get_muzzleid(itemid, avatarid)
            elseif AttachIdx == 1 then
                Data.defineID.TypeSpecificID, isrefresh = _G.get_forgripid(itemid, avatarid)
            elseif AttachIdx == 2 then
                Data.defineID.TypeSpecificID, isrefresh = _G.get_magazinesid(itemid, avatarid)
            elseif AttachIdx == 3 then
                Data.defineID.TypeSpecificID, isrefresh = _G.get_stockid(itemid, avatarid)
            elseif AttachIdx == 4 then
                Data.defineID.TypeSpecificID, isrefresh = _G.get_scopeid(itemid, avatarid)
            end
            
            if isrefresh then
                array:Set(AttachIdx, Data)
                CurWeapon:DelayHandleAvatarMeshChanged()
            end
        end
    end
end

function _G.ResetMatchState()
    _G.MatchEndMessageShown = false
    _G.LastKillTime = {}
    for k in pairs(_G.AlreadyChangedSet) do
        _G.AlreadyChangedSet[k] = nil
    end
    for k in pairs(_G.DeadBoxSkins) do
        _G.DeadBoxSkins[k] = nil
    end
end

local function ShowMatchEndMessage(message)
    pcall(function()
        local CommonMsgBoxMgr = require("client.slua.logic.common.logic_common_msg_box")
        if CommonMsgBoxMgr then
            CommonMsgBoxMgr.Show(1, "ULTIMATE ENGINE", message, function() end)
        end
    end)
end

local function GetRandomEndMessage(rank, kills)
    local messages = {
        "Congratulations! You fought well!",
        "Good game! See you on the battlefield!",
        "Well played soldier!",
        "Victory is in your blood!",
        "Another battle, another victory!",
        "You are a true champion!",
        "The battlefield honors you!",
        "Great performance today!",
        "Your skills are impressive!",
        "Keep up the good work!",
        "You made your team proud!",
        "Legendary performance!",
        "You are unstoppable!",
        "Fear the reaper! You are death itself!",
        "UltimateEngine sends their regards!"
    }
    
    if rank == 1 then
        table.insert(messages, "WINNER WINNER CHICKEN DINNER!")
        table.insert(messages, "You are the last one standing! AMAZING!")
        table.insert(messages, "CHAMPION! You dominated the battlefield!")
    elseif rank <= 5 then
        table.insert(messages, "Top 5 finish! Excellent work!")
        table.insert(messages, "Almost there! Next time you will win!")
    end
    
    if kills >= 15 then
        table.insert(messages, "HATTRICK! " .. kills .. " kills! You are a beast!")
    elseif kills >= 10 then
        table.insert(messages, "Double digits! " .. kills .. " kills! Impressive!")
    elseif kills >= 5 then
        table.insert(messages, "Solid " .. kills .. " kills! Well done!")
    end
    
    return messages[math.random(#messages)]
end

local function OnMatchEnd()
    if _G.MatchEndMessageShown then return end
    
    pcall(function()
        local GameState = slua_GameFrontendHUD and slua_GameFrontendHUD:GetGameState()
        if not GameState then return end
        
        local PlayerController = slua_GameFrontendHUD:GetPlayerController()
        if not PlayerController then return end
        
        local MyKills = 0
        if _G.killCountInfo then
            for weapon, kills in pairs(_G.killCountInfo) do
                MyKills = MyKills + kills
            end
        end
        
        local MyRank = 99
        local TeamRank = GameState:GetTeamRank()
        if TeamRank and TeamRank > 0 then
            MyRank = TeamRank
        end
        
        local message = GetRandomEndMessage(MyRank, MyKills)
        message = message .. "\n\nRank: " .. MyRank .. "\nKills: " .. MyKills .. "\n\nUltimateEngine"
        
        ShowMatchEndMessage(message)
        _G.MatchEndMessageShown = true
        _G.ResetMatchState()
    end)
end

local function CheckGameEndLoop()
    pcall(function()
        local GameState = slua_GameFrontendHUD and slua_GameFrontendHUD:GetGameState()
        if GameState and GameState.bIsMatchEnd and not _G.MatchEndMessageShown then
            OnMatchEnd()
        end
    end)
end

local function GameAvatarHandlerweapons()
    pcall(function()
        local PlayerController = slua_GameFrontendHUD and slua_GameFrontendHUD:GetPlayerController()
        if not PlayerController then return end
        
        local uCharacter = PlayerController:GetPlayerCharacterSafety()
        if not uCharacter then return end
        
        local currweapon = uCharacter:GetCurrentWeapon()
        if currweapon and slua.isValid(currweapon) then
            local skinid = slua.IndexReference(currweapon.synData:Get(7), "defineID").TypeSpecificID
            local weaponid = currweapon:GetItemDefineID().TypeSpecificID
            
            if skinid ~= _G.lastAppliedSkin[weaponid] then
                _G.apply_attachment(currweapon, skinid)
                _G.lastAppliedSkin[weaponid] = skinid
            end
        end
    end)
end

local function GameAvatarHandlerkillcounter()
    pcall(_G.ForceUpdateKillCounterUI)
end

local function Lobby_Avatar_Handler()
    pcall(function()
        _G.ReadConfigFile()
        _G.CheckLobbyThemeChanges()
        _G.GameAvatarHandlerplayers()
        _G.HandlePetLogic()
    end)
end

local function Game_Avatar_Handler()
    pcall(_G.GameAvatarHandlerplayers)
end

