-- Skin Level Override

local SKIN_LEVEL = 100

function hook_skin_level()

    local collect_mod = ModuleManager.GetModule(
        ModuleManager.LobbyModuleConfig.collect_module
    )

    if not collect_mod then
        return false
    end


    -- Level By Score
    if collect_mod.GetLevelByScore then

        local old = collect_mod.GetLevelByScore

        collect_mod.GetLevelByScore = function(self, score)

            if score and score >= 0 then
                return SKIN_LEVEL, SKIN_LEVEL, SKIN_LEVEL, 0, 0
            end

            return old(self, score)
        end
    end


    -- Level Data
    if collect_mod.GetLevelDataByScore then

        local old = collect_mod.GetLevelDataByScore

        collect_mod.GetLevelDataByScore = function(self, score, isSeason)

            if score and score >= 0 then
                return SKIN_LEVEL, "", SKIN_LEVEL
            end

            return old(self, score, isSeason)
        end
    end


    -- Season Level
    if collect_mod.GetSeasonLevelByScore then

        local old = collect_mod.GetSeasonLevelByScore

        collect_mod.GetSeasonLevelByScore = function(self, score, ...)

            if score and score >= 0 then
                return SKIN_LEVEL, false, ""
            end

            return old(self, score, ...)
        end
    end


    return true
end




pcall(hook_skin_level)














